import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';
import toast from 'react-hot-toast';

export default function Profile() {
  const { user, updateUser } = useAuth();
  const [form, setForm] = useState({ name: user?.name || '', phone: user?.phone || '', department: user?.department || '' });
  const [pwForm, setPwForm] = useState({ currentPassword: '', newPassword: '', confirm: '' });
  const [loading, setLoading] = useState(false);
  const [pwLoading, setPwLoading] = useState(false);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleProfileUpdate = async () => {
    setLoading(true);
    try {
      const res = await api.put(`/users/${user._id}`, form);
      updateUser(res.data.user);
      toast.success('Profile updated!');
    } catch (e) { toast.error(e.response?.data?.message || 'Error'); }
    finally { setLoading(false); }
  };

  const handlePasswordChange = async () => {
    if (!pwForm.currentPassword || !pwForm.newPassword) return toast.error('All fields required');
    if (pwForm.newPassword !== pwForm.confirm) return toast.error('Passwords do not match');
    if (pwForm.newPassword.length < 6) return toast.error('Password too short (min 6)');
    setPwLoading(true);
    try {
      await api.put('/auth/change-password', { currentPassword: pwForm.currentPassword, newPassword: pwForm.newPassword });
      toast.success('Password changed!');
      setPwForm({ currentPassword: '', newPassword: '', confirm: '' });
    } catch (e) { toast.error(e.response?.data?.message || 'Error'); }
    finally { setPwLoading(false); }
  };

  const ROLE_COLOR = { admin: 'var(--mauve)', security: 'var(--blue)', employee: 'var(--green)', visitor: 'var(--peach)' };

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">My Profile</h1>
          <p className="page-subtitle">Manage your account settings</p>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '280px 1fr', gap: '1.5rem', alignItems: 'start' }}>
        {/* Avatar Card */}
        <div className="card" style={{ textAlign: 'center' }}>
          <div className="avatar avatar-xl" style={{ margin: '0 auto 1rem', background: ROLE_COLOR[user?.role] || 'var(--surface1)', fontSize: '2.5rem' }}>
            {user?.photo ? <img src={`http://localhost:5000${user.photo}`} alt="" /> : user?.name?.charAt(0).toUpperCase()}
          </div>
          <h2 style={{ fontWeight: 700, color: 'var(--text)', fontSize: '1.1rem' }}>{user?.name}</h2>
          <p style={{ color: 'var(--subtext0)', fontSize: '0.85rem', marginTop: '0.2rem' }}>{user?.email}</p>
          <div style={{ marginTop: '0.75rem' }}>
            <span className="badge" style={{ background: `${ROLE_COLOR[user?.role]}22`, color: ROLE_COLOR[user?.role] }}>
              {user?.role?.toUpperCase()}
            </span>
          </div>
          <div className="divider" />
          <div style={{ textAlign: 'left', display: 'flex', flexDirection: 'column', gap: '0.6rem' }}>
            {user?.department && (
              <div style={{ fontSize: '0.83rem' }}>
                <span style={{ color: 'var(--subtext0)' }}>Department: </span>
                <span style={{ color: 'var(--text)' }}>{user.department}</span>
              </div>
            )}
            {user?.phone && (
              <div style={{ fontSize: '0.83rem' }}>
                <span style={{ color: 'var(--subtext0)' }}>Phone: </span>
                <span style={{ color: 'var(--text)' }}>{user.phone}</span>
              </div>
            )}
            <div style={{ fontSize: '0.83rem' }}>
              <span style={{ color: 'var(--subtext0)' }}>Member since: </span>
              <span style={{ color: 'var(--text)' }}>{user?.createdAt ? new Date(user.createdAt).toLocaleDateString() : '—'}</span>
            </div>
          </div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
          {/* Edit Profile */}
          <div className="card">
            <h3 style={{ fontWeight: 600, marginBottom: '1.25rem' }}>✏️ Edit Profile</h3>
            <div className="grid-2">
              <div className="form-group"><label className="form-label">Full Name</label><input className="form-input" value={form.name} onChange={e => set('name', e.target.value)} /></div>
              <div className="form-group"><label className="form-label">Phone</label><input className="form-input" value={form.phone} onChange={e => set('phone', e.target.value)} /></div>
              <div className="form-group"><label className="form-label">Department</label><input className="form-input" value={form.department} onChange={e => set('department', e.target.value)} /></div>
            </div>
            <div style={{ marginTop: '1rem' }}>
              <button className="btn btn-primary" onClick={handleProfileUpdate} disabled={loading}>{loading ? <span className="spinner" /> : '💾 Save Changes'}</button>
            </div>
          </div>

          {/* Change Password */}
          <div className="card">
            <h3 style={{ fontWeight: 600, marginBottom: '1.25rem' }}>🔐 Change Password</h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', maxWidth: 400 }}>
              <div className="form-group"><label className="form-label">Current Password</label><input className="form-input" type="password" value={pwForm.currentPassword} onChange={e => setPwForm(f => ({ ...f, currentPassword: e.target.value }))} /></div>
              <div className="form-group"><label className="form-label">New Password</label><input className="form-input" type="password" value={pwForm.newPassword} onChange={e => setPwForm(f => ({ ...f, newPassword: e.target.value }))} /></div>
              <div className="form-group"><label className="form-label">Confirm New Password</label><input className="form-input" type="password" value={pwForm.confirm} onChange={e => setPwForm(f => ({ ...f, confirm: e.target.value }))} /></div>
              <div style={{ marginTop: '0.5rem' }}>
                <button className="btn btn-secondary" onClick={handlePasswordChange} disabled={pwLoading}>{pwLoading ? <span className="spinner" /> : '🔑 Update Password'}</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
